    width: 25%;
    min-width: 260px;
    background: #fff;
    border-left: 1px solid #dee2e6;
    display: flex;
    flex-direction: column;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 14px 16px;
    border-bottom: 1px solid #dee2e6;
}

.thread-header h5 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
}

.close-btn {
    background: none;
    border: none;
    font-size: 1.1rem;
    cursor: pointer;
    color: #6c757d;
    padding: 4px 8px;
    border-radius: 4px;
}

.close-btn:hover {
    background: #e9ecef;
    color: #212529;
}

.thread-root-quote {
    padding: 12px 16px;
    background: #f1f3f5;
    border-bottom: 1px solid #dee2e6;
    border-left: 3px solid #89b4fa;
    margin: 0;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 8px 16px;
}

.thread-reply {
    padding: 8px 0;
    border-bottom: 1px solid #f1f3f5;
}
"}

